[66] يُنظر: ((تفسير ابن جرير)) (13/600)، ((تفسير ابن كثير)) (4/479)، ((تفسير السعدي)) (ص: 422).    قال ابنُ كثيرٍ: (وَفِي ذَلِكُمْ بَلَاءٌ مِنْ رَبِّكُمْ عَظِيمٌ، أي: نِعمةٌ عَظيمةٌ منه عليكم في ذلك، أنتم عاجِزونَ عنِ القيامِ بشُكْرِها. وقِيلَ: وفيما كان يَصنَعُه بكم قَومُ فِرعونَ مِن تلك الأفاعيلِ، بَلَاءٌ، أي: اختبارٌ عَظيمٌ. ويَحْتمِلُ أنْ يكونَ المُرادُ هذا وهذا- واللهُ أعلمُ- كما قال تعالى: وَبَلَوْنَاهُمْ بِالْحَسَنَاتِ وَالسَّيِّئَاتِ لَعَلَّهُمْ يَرْجِعُونَ
[الأعراف: 168]
). ((تفسير ابن كثير)) (4/479).

[68] يُنظر: ((تفسير ابن جرير)) (13/600، 601)، ((تفسير القرطبي)) (9/343)، ((تفسير ابن كثير)) (4/479).     قال القرطبي: (قيل: هو مِن قولِ موسى لقومِه. وقيل: هو من قولِ الله، أي: واذكُرْ- يا محمَّدُ- إذ قال ربُّك كذا). ((تفسير القرطبي)) (9/343). قال ابنُ كثير: (ويحتملُ أن يكونَ المعنى: وإذ أقسمَ رَبُّكم وآلى بعزَّتِه وجلالِه وكبريائِه، كما قال: وَإِذْ تَأَذَّنَ رَبُّكَ لَيَبْعَثَنَّ عَلَيْهِمْ إِلَى يَوْمِ الْقِيَامَةِ مَنْ يَسُومُهُمْ سُوءَ الْعَذَابِ
[الأعراف: 167]
). ((تفسير ابن كثير)) (4/479).

[205] يُنظر: ((تفسير ابن جرير)) (13/618)، ((تفسير البغوي)) (3/33)، ((تفسير ابن كثير)) (4/485). قال ابن كثير: (وَيُسْقَى مِنْ مَاءٍ صَدِيدٍ أي: في النَّارِ، ليس له شرابٌ إلَّا من حميمٍ أو غسَّاقٍ، فهذا في غايةِ الحرارة، وهذا في غايةِ البَردِ والنَّتن، كما قال: هَذَا فَلْيَذُوقُوهُ حَمِيمٌ وغَسَّاقٌ * وَآخَرُ مِنْ شَكْلِهِ أَزْوَاجٌ
[ص: 57- 58]
). ((تفسير ابن كثير)) (4/485).

[461] يُنظر: ((تفسير مقاتل بن سليمان)) (2/408)، ((تفسير ابن عطية)) (3/341)،  ((مدارج السالكين)) لابن القيم (1/60)، ((تفسير العليمي)) (3/526). وممن اختار هذا المعنى المذكورَ: مقاتلُ بنُ سليمانَ، وابنُ عطيةَ، وابنُ القيمِ، والعليمي. يُنظر: المصادر السابقة. قال مقاتلُ بنُ سليمانَ: (نظيرُها- في الأحزابِ وَيُعَذِّبَ الْمُنَافِقِينَ إِنْ شَاءَ أَوْ يَتُوبَ عَلَيْهِمْ إِنَّ اللهَ كَانَ غَفُورًا رَحِيمًا
[الأحزاب: 24]
). ((تفسير مقاتل بن سليمان)) (2/408). وقيل: المرادُ: ومَن عصاني فيما دونَ الشركِ. وممن اختاره: مقاتلُ بنُ حيان، والواحدي، وهو ظاهرُ اختيارِ السعدي. يُنظر: ((تفسير ابن الجوزي)) (2/515)، ((الوجيز)) للواحدي (ص: 584)، ((تفسير السعدي)) (ص: 427). وقيل: هذا تفويضٌ للأمرِ إلى الله عزَّ وجلَّ، وردٌّ إلى مشيئتِه، لا طَلَبٌ ودعاءٌ بالمغفرةِ لهم. وممن اختار هذا المعنَى: ابنُ كثيرٍ، ومحمد رشيد رضا، وابنُ عاشور. يُنظر: ((تفسير ابن كثير)) (4/513)، ((تفسير المنار)) (10/87)، ((تفسير ابن عاشور)) (13/240). قال ابنُ عاشورٍ: (المعنى: ومَن عصاني أُفَوِّضُ أمْرَه إلى رَحمَتِك وغُفرانِك. وليس المَقصودُ الدُّعاءَ بالمَغفرةِ لمَن عصى. وهذا مِن غَلبةِ الحِلْمِ على إبراهيمَ عليه السَّلامُ، [وخَشيتِه] مِن استئصالِ عُصاةِ ذُرِّيَّتِه). ((تفسير ابن عاشور)) (13/240).

[478] قال ابنُ جرير: (هذا دعاءٌ مِن إبراهيم صلواتُ اللهِ عليه لوالديه بالمغفرة، واستغفارٌ منه لهما، وقد أخبر الله عزَّ ذِكرُه أنَّه لم يكن اسْتِغْفَارُ إِبْرَاهِيمَ لِأَبِيهِ إِلَّا عَنْ مَوْعِدَةٍ وَعَدَهَا إِيَّاهُ فَلَمَّا تَبَيَّنَ لَهُ أَنَّهُ عَدُوٌّ لِلَّهِ تَبَرَّأَ مِنْهُ إِنَّ إِبْرَاهِيمَ لَأَوَّاهٌ حَلِيمٌ
[التوبة: 114]
). ((تفسير ابن جرير)) (13/703). ويُنظر: ((تفسير ابن كثير)) (4/514).

[575] قيل:كان مكرُهم شركَهم باللهِ وافتراءَهم عليه. وممن اختار هذا المعني: ابنُ جرير، والقرطبي. يُنظر: ((تفسير ابن جرير)) (13/721)، ((تفسير القرطبي)) (9/380). وقال السمعاني: (قولُه تعالَى: (وَقَدْ مَكَرُوا مَكْرَهمْ أَي: كادُوا كيدَهم). ((تفسير السمعاني)) (3/124). وقال ابنُ عاشور: (والمكرُ: تَبْييتُ فعلِ السُّوءِ بالغيرِ وإضمارُه). ((تفسير ابن عاشور)) (13/250). وهذا القول أيضًا هو ظاهرُ اختيارِ البيضاوي، والشوكاني، والسعدي. يُنظر: ((تفسير البيضاوي)) (3/203)، ((تفسير الشوكاني)) (3/140)، ((تفسير السعدي)) (ص: 427). قال الواحدي: (وَقَدْ مَكَرُوا مَكْرَهُمْ يعني: مكرَهم بالنبيِّ صلَّى الله عليه وسلَّم وما همُّوا به مِن قتلِه أو نفيِه). ((الوجيز)) (ص: 586). وقال الرازي: (وذلك المكرُ هو الذي ذكَره الله تعالى في قولِه: وَإِذْ يَمْكُرُ بِكَ الَّذِينَ كَفَرُوا لِيُثْبِتُوكَ أَوْ يَقْتُلُوكَ أَوْ يُخْرِجُوكَ
[الأنفال: 30]
). ((تفسير الرازي)) (19/110). وهذا على اعتبارِ أنَّ الضميرَ في مَكَرُوا عائدٌ على قومِ الرسولِ صلَّى الله عليه وسلَّم. يُنظر: ((تفسير أبي حيان)) (6/454).
